/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000007;
    const V_MAX = 5000;

    // --- Phase 1: Precalculation ---

    /**
     * Calculates the sum of digits of a number.
     * @param {number} n
     * @returns {number}
     */
    const calculateDigitSum = (n) => {
        let sum = 0;
        let strN = String(n);
        for (let i = 0; i < strN.length; i++) {
            sum += parseInt(strN[i]);
        }
        return sum;
    };

    // Map[D] stores a list of numbers V <= 5000 such that S(V) = D.
    // We only need to store up to D=50 based on input constraints, but V_MAX ensures D<=31 actually.
    const Map = new Array(51).fill(0).map(() => []);

    for (let V = 0; V <= V_MAX; V++) {
        const D = calculateDigitSum(V);
        if (D <= 50) {
            Map[D].push(V);
        }
    }

    // --- Phase 2: Dynamic Programming ---

    // DP_prev[V]: Count of valid sequences ending at the previous index (i-1) with value V.
    // Size V_MAX + 1 (for values 0 to 5000).
    let DP_prev = new Array(V_MAX + 1).fill(0);

    const N = digitSum.length;

    // Base Case (i = 0)
    const D0 = digitSum[0];
    if (D0 >= 0 && D0 <= 50) {
        for (const V of Map[D0]) {
            DP_prev[V] = 1;
        }
    } else {
        // If the first required digit sum is impossible
        return 0;
    }

    // Iteration (i = 1 to N-1)
    for (let i = 1; i < N; i++) {
        const D_new = digitSum[i];
        let DP_current = new Array(V_MAX + 1).fill(0);

        if (D_new < 0 || D_new > 50) {
            return 0;
        }

        // 1. Calculate Prefix Sum of DP_prev
        // PrefixSum[V] = Sum of DP_prev[k] for k=0 to V, modulo MOD.
        let PrefixSum = new Array(V_MAX + 1).fill(0);
        PrefixSum[0] = DP_prev[0];

        for (let V = 1; V <= V_MAX; V++) {
            PrefixSum[V] = (PrefixSum[V - 1] + DP_prev[V]) % MOD;
        }

        // 2. Calculate DP_current based on PrefixSum
        // DP_current[V_new] = Sum of DP_prev[V_old] where V_old <= V_new
        for (const V_new of Map[D_new]) {
            // The count is the total number of sequences ending in V_old <= V_new
            DP_current[V_new] = PrefixSum[V_new];
        }

        DP_prev = DP_current;
    }

    // Final Result: Sum all counts in the last DP array
    let totalCount = 0;
    for (let V = 0; V <= V_MAX; V++) {
        totalCount = (totalCount + DP_prev[V]) % MOD;
    }

    return totalCount;
}

